CustomField.formula:
IF(Total_of_Submissions__c = 0, 'No Submission',
   IF(Approved__c = 1, 'Finalised - Approved', 
      IF(TEXT(b3o__Contact__r.TR1__Candidate_Status__c) = 'Inactive', 'Hold - Inactive Candidate',
         IF( AND(Total_of_Submissions__c - of_Rejected_Submissions__c !=  Total_Assigned__c,  of_Submissions_Pending_Review__c =0), 'Pending Submission/Update', 'Pending Review' 
         )
      )
   )
)
